function parseArgs(): CliConfig {
  const byKey = new Map<string, string>();
  for (const raw of process.argv.slice(2)) {
    if (!raw.startsWith("--")) continue;
    const [key, ...rest] = raw.slice(2).split("=");
    byKey.set(key.trim(), rest.join("="));
  }

  const weeksRaw = Number(byKey.get("weeks"));
  const requestedWeeks = Number.isFinite(weeksRaw) ? Math.max(1, Math.floor(weeksRaw)) : RESEARCH_MAX_WEEKS;
  const weeks = Math.min(requestedWeeks, RESEARCH_MAX_WEEKS);
  const outPath =
    byKey.get("out")?.trim() || "app/reports/bias-gate/strategy-comparison-latest.json";
  const sweepRaw = String(byKey.get("sweep") ?? "").trim().toLowerCase();
  const sweep = sweepRaw === "1" || sweepRaw === "true" || sweepRaw === "yes" || sweepRaw === "on";
  const reduceAsSkipRaw = String(byKey.get("reduce-as-skip") ?? "").trim().toLowerCase();
  const reduceAsSkip =
    reduceAsSkipRaw === "1" ||
    reduceAsSkipRaw === "true" ||
    reduceAsSkipRaw === "yes" ||
    reduceAsSkipRaw === "on";
  const sweepSkipValues = parseNumberList(byKey.get("sweep-skip"), [90, 92.5, 95]);
  const sweepReduceValues = parseNumberList(byKey.get("sweep-reduce"), [75, 80, 85]);
  const gammaModeRaw = String(byKey.get("gamma-mode") ?? process.env.GAMMA_MODE ?? "off").trim().toLowerCase();
  const gammaMode: GammaMode = gammaModeRaw === "only" ? "only" : gammaModeRaw === "additive" ? "additive" : "off";
  const gammaNeutralRaw = String(byKey.get("gamma-neutral-policy") ?? process.env.GAMMA_NEUTRAL_POLICY ?? "pass")
    .trim()
    .toLowerCase();
  const gammaNeutralPolicy: GammaNeutralPolicy =
    gammaNeutralRaw === "skip" ? "skip" : gammaNeutralRaw === "no_data" ? "no_data" : "pass";
  const gammaWeekOpenCsv = byKey.get("gamma-week-open-csv")?.trim() || process.env.GAMMA_WEEK_OPEN_CSV || DEFAULT_GAMMA_WEEK_OPEN_CSV;
  const gammaPairMapCsv = byKey.get("gamma-pair-map-csv")?.trim() || process.env.GAMMA_PAIR_MAP_CSV || DEFAULT_GAMMA_PAIR_MAP_CSV;

  return {
    weeksRequested: requestedWeeks,
    weeks,
    outPath,
    sweep,
    sweepSkipValues,
    sweepReduceValues,
    reduceAsSkip,
    gammaMode,
    gammaNeutralPolicy,
    gammaWeekOpenCsv,
    gammaPairMapCsv,
  };
}

function round(value: number, decimals = 4): number {
  const scale = 10 ** decimals;
  return Math.round(value * scale) / scale;
}

function toAssetClassId(value: unknown): AssetClassId | null {
  const raw = String(value ?? "").trim().toLowerCase();
  if (raw === "fx" || raw === "indices" || raw === "crypto" || raw === "commodities") {
    return raw;
  }
  return null;
}

function parseNumberList(raw: string | undefined, fallback: number[]): number[] {
  if (!raw || raw.trim().length === 0) return fallback;
  const parsed = raw
    .split(",")
    .map((part) => Number(part.trim()))
    .filter((value) => Number.isFinite(value));
  return parsed.length > 0 ? parsed : fallback;
}

function parseCsvLine(line: string): string[] {
  const out: string[] = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i += 1) {
    const ch = line[i];
    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }
    if (ch === "," && !inQuotes) {
      out.push(current.trim());
      current = "";
      continue;
    }
    current += ch;
  }
  out.push(current.trim());
  return out;
}

function parseCsvObjects(filePath: string): Array<Record<string, string>> {
  const resolved = path.resolve(process.cwd(), filePath);
  if (!existsSync(resolved)) return [];
  const raw = readFileSync(resolved, "utf8");
  const lines = raw.split(/\r?\n/).filter((line) => line.trim().length > 0);
  if (lines.length < 2) return [];
  const headers = parseCsvLine(lines[0]).map((header) => header.trim().toLowerCase());
  const out: Array<Record<string, string>> = [];
  for (const line of lines.slice(1)) {
    const values = parseCsvLine(line);
    const row: Record<string, string> = {};
    headers.forEach((header, index) => {
      row[header] = values[index] ?? "";
    });
    out.push(row);
  }
  return out;
}

